// Do not edit this file as it will be overwritten if HAMR codegen is rerun

//! Property gen_range_sanity -- non-disabling VCs, part of the independence proof,
//! for every MHIP transition pair (per direction whose firing member is a
//! component): pre-assertions preservation (the firing does not disable another
//! transition -- its pre-assertions still hold) and post-assertions preservation
//! (the firing preserves another transition's established post-assertions).
//! Together with the property-independent Commutativity VCs, these establish
//! that concurrently-enabled transitions do not interfere.
//! Each proof fn has an empty body: Verus discharges `requires ==> ensures`
//! via SMT; add proof hints in the body if a VC does not discharge.

#![allow(non_snake_case)]
#![allow(unused_variables)]
#![allow(unused_imports)]

use vstd::prelude::*;

use crate::assertions::*;
use crate::gen_range_sanity::assertions::*;
use crate::system_state::SystemState;
use crate::write_frames::*;

verus! {

/** VC[19]: Pre-Assertions Preservation -- INCX firing does not disable DECY (preserves its pre-assertions; MHIP pair t2/t4) */
pub proof fn vc_pre_assertions_preservation_incx_decy(pre: SystemState, post: SystemState)
  requires
    true /* before_incx has no assertion */,
    true /* before_decy has no assertion */,
    incx_global_write_frame(pre, post),
  ensures
    true /* before_decy has no assertion */,
{}

/** VC[20]: Pre-Assertions Preservation -- DECY firing does not disable INCX (preserves its pre-assertions; MHIP pair t2/t4) */
pub proof fn vc_pre_assertions_preservation_decy_incx(pre: SystemState, post: SystemState)
  requires
    true /* before_incx has no assertion */,
    true /* before_decy has no assertion */,
    decy_global_write_frame(pre, post),
  ensures
    true /* before_incx has no assertion */,
{}

/** VC[21]: Post-Assertions Preservation -- INCX firing preserves DECY's post-assertions (MHIP pair t2/t4) */
pub proof fn vc_post_assertions_preservation_incx_decy(pre: SystemState, post: SystemState)
  requires
    true /* before_incx has no assertion */,
    true /* after_decy has no assertion */,
    incx_global_write_frame(pre, post),
  ensures
    true /* after_decy has no assertion */,
{}

/** VC[22]: Post-Assertions Preservation -- DECY firing preserves INCX's post-assertions (MHIP pair t2/t4) */
pub proof fn vc_post_assertions_preservation_decy_incx(pre: SystemState, post: SystemState)
  requires
    true /* before_decy has no assertion */,
    true /* after_incx has no assertion */,
    decy_global_write_frame(pre, post),
  ensures
    true /* after_incx has no assertion */,
{}

/** VC[23]: Pre-Assertions Preservation -- CLAMPX firing does not disable DECY (preserves its pre-assertions; MHIP pair t3/t4) */
pub proof fn vc_pre_assertions_preservation_clampx_decy(pre: SystemState, post: SystemState)
  requires
    true /* after_incx has no assertion */,
    true /* before_decy has no assertion */,
    clampx_global_write_frame(pre, post),
  ensures
    true /* before_decy has no assertion */,
{}

/** VC[24]: Pre-Assertions Preservation -- DECY firing does not disable CLAMPX (preserves its pre-assertions; MHIP pair t3/t4) */
pub proof fn vc_pre_assertions_preservation_decy_clampx(pre: SystemState, post: SystemState)
  requires
    true /* after_incx has no assertion */,
    true /* before_decy has no assertion */,
    decy_global_write_frame(pre, post),
  ensures
    true /* after_incx has no assertion */,
{}

/** VC[25]: Post-Assertions Preservation -- CLAMPX firing preserves DECY's post-assertions (MHIP pair t3/t4) */
pub proof fn vc_post_assertions_preservation_clampx_decy(pre: SystemState, post: SystemState)
  requires
    true /* after_incx has no assertion */,
    true /* after_decy has no assertion */,
    clampx_global_write_frame(pre, post),
  ensures
    true /* after_decy has no assertion */,
{}

/** VC[26]: Post-Assertions Preservation -- DECY firing preserves CLAMPX's post-assertions (MHIP pair t3/t4) */
pub proof fn vc_post_assertions_preservation_decy_clampx(pre: SystemState, post: SystemState)
  requires
    true /* before_decy has no assertion */,
    true /* after_clampx has no assertion */,
    decy_global_write_frame(pre, post),
  ensures
    true /* after_clampx has no assertion */,
{}

} // verus!
